class Solution:
    def treeQueries(self, root, queries):
        # naive: for each query, physically rebuild height excluding that subtree
        def height(node):
            if not node:
                return -1
            return 1 + max(height(node.left), height(node.right))
        import sys
        sys.setrecursionlimit(300000)
        ans = []
        for q in queries:
            def h_excl(node):
                if not node or node.val == q:
                    return -1
                return 1 + max(h_excl(node.left), h_excl(node.right))
            ans.append(h_excl(root))
        return ans

