import sys
class Solution:
    def treeQueries(self, root, queries):
        sys.setrecursionlimit(300000)
        height = {None: -1}
        def calc_h(node):
            if not node:
                return -1
            h = 1 + max(calc_h(node.left), calc_h(node.right))
            height[node] = h
            return h
        calc_h(root)
        answer = {}
        def dfs(node, depth, rest):
            # rest = deepest level (in edges from root) reachable on a path
            # that never enters this node's subtree
            if not node:
                return
            answer[node.val] = rest
            lh = height[node.left]
            rh = height[node.right]
            dfs(node.left, depth + 1, max(rest, depth + 1 + rh))
            dfs(node.right, depth + 1, max(rest, depth + 1 + lh))
        dfs(root, 0, 0)
        return [answer[q] for q in queries]

