var treeQueries = function(root, queries) {
    const height = new Map();
    const calcH = (node) => {
        if (!node) return -1;
        const h = 1 + Math.max(calcH(node.left), calcH(node.right));
        height.set(node, h);
        return h;
    };
    calcH(root);
    const hOf = (node) => node ? height.get(node) : -1;
    const answer = new Map();
    const stack = [[root, 0, 0]];
    while (stack.length) {
        const [node, depth, rest] = stack.pop();
        if (!node) continue;
        answer.set(node.val, rest);
        const lh = hOf(node.left);
        const rh = hOf(node.right);
        stack.push([node.left, depth + 1, Math.max(rest, depth + 1 + rh)]);
        stack.push([node.right, depth + 1, Math.max(rest, depth + 1 + lh)]);
    }
    return queries.map(q => answer.get(q));
};
